3. Project Aim
The project aims to develop a visual analytics prototype that allows users to:

compare tourism conditions across the pre-COVID, COVID shock, and recovery periods;
evaluate how the Chinese source market changed relative to total visitor arrivals;
examine how visitor arrivals, hotel occupancy, and stay duration move together;
group monthly observations into interpretable tourism market states; and
explain hotel occupancy outcomes using rule-based and ensemble models.

1.2Importing Data


Show the code
find_project_root &lt;- function(start = getwd()) {
  current &lt;- normalizePath(start, winslash = "/", mustWork = TRUE)

  repeat {
    if (file.exists(file.path(current, "_quarto.yml"))) {
      return(current)
    }

    parent &lt;- dirname(current)
    if (identical(parent, current)) {
      stop("Project root not found. Expected to locate _quarto.yml.")
    }

    current &lt;- parent
  }
}

project_root &lt;- find_project_root()
module_dir &lt;- file.path(project_root, "team", "jin-qinhao", "Take-Home-Exercise2")
data_dir &lt;- file.path(module_dir, "data")
raw_path &lt;- file.path(data_dir, "Name your insight (2).xlsx")
processed_dir &lt;- data_dir
artifact_export_enabled &lt;- identical(
  tolower(Sys.getenv("WRITE_TAKE_HOME_EX2_ARTIFACTS", "false")),
  "true"
)

export_note &lt;- function(path_label) {
  message(
    "Artifact export skipped during render. ",
    "Set WRITE_TAKE_HOME_EX2_ARTIFACTS=true to regenerate tracked files under: ",
    path_label
  )
}

if (artifact_export_enabled) {
  dir.create(processed_dir, recursive = TRUE, showWarnings = FALSE)
}

1.9Export the cleaned data


Show the code
if (artifact_export_enabled) {
  readr::write_csv(monthly_clean, file.path(processed_dir, "tourism_monthly_clean.csv"))
  readr::write_csv(decision_tree_ready, file.path(processed_dir, "tourism_decision_tree_ready.csv"))
  readr::write_csv(analysis_ready, file.path(processed_dir, "tourism_four_part_analysis_ready.csv"))

  writexl::write_xlsx(
    list(
      monthly_clean = monthly_clean,
      decision_tree_ready = decision_tree_ready,
      analysis_ready_all = analysis_ready
    ),
    path = file.path(processed_dir, "tourism_four_part_analysis_ready.xlsx")
  )
} else {
  export_note(processed_dir)
}
